-- Africa cities (SimpleMaps World Cities Basic, CC BY 4.0) pop>=15000 — part 3/3
ON CONFLICT (id) DO NOTHING;

-- Flip is_leaf on admin1 (and countries) that now have city descendants
UPDATE atoms a SET is_leaf=false, updated_at=now()
WHERE a.realm_id='geography' AND a.depth IN (4,5) AND a.path LIKE 'Geography / Countries / Africa / %'
  AND EXISTS (SELECT 1 FROM atoms c WHERE c.path LIKE a.path || ' / %');